// interface: open, mergeable, extendable
interface User { id: string; name: string; }
interface User { email: string; } // declaration merging -> User now has all three

// type alias: closed, but expressive
type Id = string | number;            // unions
type Pair = [number, number];         // tuples
type Nullable<T> = T | null;          // generic alias
type Handler = (e: Event) => void;    // function type

// Both can model an object; pick interface for public, extensible contracts.
interface Point { x: number; y: number; }
type PointAlias = { x: number; y: number };

interface Named { name: string; }
class Dog { constructor(public name: string, public breed: string) {} }

function greet(n: Named) { return `Hi ${n.name}`; }

// Dog was never declared to implement Named, but structurally it fits.
greet(new Dog('Rex', 'Lab')); // OK

// Excess property checks apply only to fresh object literals:
greet({ name: 'A', extra: 1 }); // ERROR: object literal may only specify known props
const obj = { name: 'A', extra: 1 };
greet(obj); // OK: not a fresh literal, structural width is fine

// Constrain K to be a key of T; return type tracks the chosen property.
function getProp<T, K extends keyof T>(obj: T, key: K): T[K] {
  return obj[key];
}

const user = { id: 1, name: 'Ada' };
const name = getProp(user, 'name'); // inferred as string
// getProp(user, 'missing'); // ERROR: 'missing' not assignable to 'id' | 'name'

// Default type parameters and constraints together:
interface Repo<T extends { id: string } = { id: string }> {
  findById(id: string): Promise<T | null>;
}

interface Config { host: string; port: number; tls: boolean; }

type PartialConfig = Partial<Config>;            // all optional
type Conn = Pick<Config, 'host' | 'port'>;       // { host; port }
type NoTls = Omit<Config, 'tls'>;                // { host; port }
type Flags = Record<string, boolean>;            // dictionary

async function load() { return { ok: true }; }
type R = ReturnType<typeof load>;                // Promise<{ ok: boolean }>
type A = Awaited<R>;                             // { ok: boolean }

// A mapped type iterates over keys and remaps each property.
type MyPartial<T> = { [K in keyof T]?: T[K] };
type MyReadonly<T> = { readonly [K in keyof T]: T[K] };

// Key remapping with 'as' lets you rename or filter keys:
type Getters<T> = {
  [K in keyof T as `get${Capitalize<string & K>}`]: () => T[K];
};
type UserGetters = Getters<{ name: string; age: number }>;
// { getName: () => string; getAge: () => number }

type NonNull<T> = T extends null | undefined ? never : T;
type Elem<T> = T extends (infer U)[] ? U : T; // infer extracts element type

// Conditional types distribute over naked union type parameters:
type Distributed = NonNull<string | null | number>; // string | number
// Wrap in a tuple to prevent distribution:
type NoDistribute<T> = [T] extends [null] ? true : false;

type Method = 'GET' | 'POST';
type Route = `/api/${string}`;
type Endpoint = `${Method} ${Route}`; // 'GET /api/...' | 'POST /api/...'

// Discriminated union: 'status' is the discriminant.
type Result<T> =
  | { status: 'loading' }
  | { status: 'success'; data: T }
  | { status: 'error'; error: Error };

function render<T>(r: Result<T>): string {
  switch (r.status) {
    case 'loading': return 'spinner';
    case 'success': return `data: ${r.data}`; // r.data is T here
    case 'error':   return r.error.message;   // r.error is Error here
    default: {
      const _exhaustive: never = r; // compile error if a case is missed
      return _exhaustive;
    }
  }
}

// Custom type guard returns a type predicate.
interface Cat { meow(): void }
interface Dog { bark(): void }
function isCat(a: Cat | Dog): a is Cat {
  return 'meow' in a;
}

async function fetchUser(id: string): Promise<{ name: string }> {
  const res = await fetch(`/users/${id}`);
  if (!res.ok) throw new Error(`HTTP ${res.status}`);
  // res.json() is Promise<any>; validate at the boundary in real code.
  return (await res.json()) as { name: string };
}

try {
  await fetchUser('1');
} catch (e) {
  // e is 'unknown' under useUnknownInCatchVariables (default in strict).
  if (e instanceof Error) console.error(e.message);
}

// TC39 Stage 3 method decorator (TS 5.0+, no experimentalDecorators flag).
function logged<This, Args extends any[], Return>(
  target: (this: This, ...args: Args) => Return,
  ctx: ClassMethodDecoratorContext
) {
  return function (this: This, ...args: Args): Return {
    console.log(`call ${String(ctx.name)}`);
    return target.call(this, ...args);
  };
}

class Service {
  @logged
  fetch(id: string) { return id; }
}

