type ApiSuccess<T> = {
  ok: true;
  status: number;
  data: T;
};

type ApiFailure = {
  ok: false;
  status: number;
  error: { code: string; message: string };
};

export type ApiResponse<T> = ApiSuccess<T> | ApiFailure;

export class ApiError extends Error {
  constructor(public code: string, message: string, public status: number) {
    super(message);
    this.name = 'ApiError';
  }
}

export function handleResponse<T>(res: ApiResponse<T>): T {
  if (res.ok) {
    // narrowed to ApiSuccess<T>: res.data is T
    return res.data;
  }
  // narrowed to ApiFailure: res.error is available
  throw new ApiError(res.error.code, res.error.message, res.status);
}

// Typed factory helpers keep call sites honest.
export const ok = <T>(data: T, status = 200): ApiResponse<T> => ({ ok: true, status, data });
export const fail = (code: string, message: string, status = 500): ApiResponse<never> =>
  ({ ok: false, status, error: { code, message } });

// Usage
const r: ApiResponse<{ id: string }> = ok({ id: 'u1' });
const user = handleResponse(r); // user: { id: string }

type Primitive = string | number | boolean | bigint | symbol | null | undefined;

export type DeepReadonly<T> =
  T extends Primitive
    ? T
    : T extends (...args: any[]) => any
      ? T // leave functions as-is
      : T extends ReadonlyArray<infer U>
        ? ReadonlyArray<DeepReadonly<U>>
        : T extends Map<infer K, infer V>
          ? ReadonlyMap<DeepReadonly<K>, DeepReadonly<V>>
          : T extends Set<infer M>
            ? ReadonlySet<DeepReadonly<M>>
            : { readonly [K in keyof T]: DeepReadonly<T[K]> };

// Usage / proof
interface Profile {
  id: string;
  prefs: { theme: 'light' | 'dark'; tags: string[] };
  greet: () => string;
}

const p: DeepReadonly<Profile> = {
  id: 'u1',
  prefs: { theme: 'dark', tags: ['a'] },
  greet: () => 'hi',
};

// p.id = 'x';                 // ERROR: id is readonly
// p.prefs.theme = 'light';    // ERROR: nested prop is readonly
// p.prefs.tags.push('b');     // ERROR: push does not exist on ReadonlyArray
p.greet();                     // OK: functions still callable
